139→    private fun copyUrlAction(post: PostModel) = PostListAction.CopyUrl(
140→        site = site,
141→        post = post,
142→        showSnackbar = showSnackbar,
143→        messageSuccess = SnackbarMessageHolder(
144→            UiStringRes(R.string.post_link_copied_to_clipboard),
145→            duration = Snackbar.LENGTH_SHORT,
146→            isImportant = false
147→        ),
148→        messageError = SnackbarMessageHolder(
149→            UiStringRes(R.string.error_copy_to_clipboard),
150→            duration = Snackbar.LENGTH_SHORT,
151→            isImportant = false
152→        )
153→    )
