193→    fun publishPost(post: PostModel) {
194→        triggerPostUploadAction.invoke(PublishPost(dispatcher, site, post))
195→    }
196→
197→    fun resolveConflictsAndEditPost(localPostId: Int) {
198→        val post = postStore.getPostByLocalPostId(localPostId)
199→        if (post != null) {
200→            performChecksAndEdit(site, post)
201→        }
202→    }
